    "cases.update_the_programme_and_reforecast.step.reforecast.why": "Giá trị của một tiến độ sống động là nó cho bạn biết bạn sẽ đến đâu, chứ không chỉ nơi bạn đã ở. Dự báo lại từ tiến độ thực tế là điều biến các con số tuần trước thành một quyết định bạn có thể hành động.",
    "cases.update_the_programme_and_reforecast.step.report.in.causes": "Chậm trễ & nguyên nhân",
    "cases.update_the_programme_and_reforecast.step.report.in.forecast": "Ngày hoàn thành dự báo lại",
    "cases.update_the_programme_and_reforecast.step.report.out.recovery": "Hành động khắc phục",
    "cases.update_the_programme_and_reforecast.step.report.out.report": "Báo cáo dự báo",
    "cases.update_the_programme_and_reforecast.step.report.title": "Báo cáo dự báo mới",
    "cases.update_the_programme_and_reforecast.step.report.what": "Phát hành dự báo đã cập nhật cho khách hàng và đội ngũ kèm lý do trình bày rõ ràng: cái gì đã dịch chuyển, bao nhiêu, tại sao, và những gì đang được làm để kéo lại tiến độ. Giữ đủ ngắn gọn để mọi người thực sự đọc.",
    "cases.update_the_programme_and_reforecast.step.report.why": "Một dự báo chỉ nằm trên màn hình lập kế hoạch không thay đổi được gì. Báo cáo rõ ràng, kèm lý do, là điều giúp khách hàng tin tưởng con số và giúp đội ngũ thống nhất kế hoạch khắc phục trước kỳ tiếp theo.",
    "cases.update_the_programme_and_reforecast.step.slippage.in.baseline": "Tiến độ baseline",
    "cases.update_the_programme_and_reforecast.step.slippage.in.forecast": "Dự báo mới",
    "cases.update_the_programme_and_reforecast.step.slippage.out.causes": "Nguyên nhân chậm trễ",
    "cases.update_the_programme_and_reforecast.step.slippage.out.slippage": "Độ chậm trễ so với baseline",
    "cases.update_the_programme_and_reforecast.step.slippage.title": "Phát hiện chậm trễ so với baseline",
    "cases.update_the_programme_and_reforecast.step.slippage.what": "So sánh dự báo lại với baseline đã đóng băng và chỉ ra nơi dự án đã chậm trễ: cột mốc nào đã dịch chuyển, thời gian dự trữ đã bị tiêu tốn bao nhiêu, và chậm trễ nào bắt nguồn từ một thay đổi thay vì từ sản xuất.",
    "cases.update_the_programme_and_reforecast.step.slippage.why": "Biết bạn đang trễ chưa đủ, bạn phải biết tại sao và trách nhiệm thuộc về ai. Gắn chậm trễ với các thay đổi là điều bảo vệ một khiếu nại gia hạn thời gian trước khi chậm trễ bị lãng quên.",
    "cases.update_the_programme_and_reforecast.title": "Cập nhật tiến độ và dự báo lại",
    "cases.validate_estimate.desc": "Đưa một bảng giá đã định giá qua các quy tắc kiểm tra hợp lệ, xử lý mọi cảnh báo và lỗi, sau đó xuất một báo cáo sạch bạn có thể trao thẳng cho khách hàng.",
    "cases.validate_estimate.step.boq.in.bill": "Bảng khối lượng đã định giá",
    "cases.validate_estimate.step.boq.in.rates": "Khối lượng và đơn giá",
    "cases.validate_estimate.step.boq.out.gaps": "Ô trống đã phát hiện",
    "cases.validate_estimate.step.boq.out.reviewed": "Bảng giá đã rà soát",
    "cases.validate_estimate.step.boq.title": "Mở bảng giá đã định giá",
    "cases.validate_estimate.step.boq.what": "Mở bảng giá bạn chuẩn bị phát hành và xác nhận mọi hạng mục đều có cả khối lượng và đơn giá. Ô trống và số không lẻ tẻ là điều đầu tiên trình kiểm tra hợp lệ sẽ săn tìm, nên rà soát nhanh bây giờ tránh bất ngờ sau này.",
    "cases.validate_estimate.step.boq.why": "Một lỗ hổng bạn bỏ sót là lỗ hổng khách hàng phát hiện trước, thường là ngay trong cuộc họp. Tự rà soát bảng giá nghĩa là bước kiểm tra hợp lệ sẽ xác nhận công việc tốt thay vì phơi bày lỗ hổng.",
    "cases.validate_estimate.step.report.in.bill": "Bảng giá đã kiểm tra hợp lệ (xanh)",
    "cases.validate_estimate.step.report.in.outcome": "Kết quả kiểm tra hợp lệ",
    "cases.validate_estimate.step.report.out.breakdown": "Phân tích chi phí chi tiết",
    "cases.validate_estimate.step.report.out.summary": "Tóm tắt điều hành",
    "cases.validate_estimate.step.report.title": "Xuất báo cáo",
    "cases.validate_estimate.step.report.what": "Khi bảng giá hiển thị xanh, xuất bản tóm tắt điều hành cùng phân tích chi tiết. Báo cáo trình bày phân chia chi phí và kết quả kiểm tra hợp lệ trong một tài liệu.",
    "cases.validate_estimate.step.report.why": "Một báo cáo được hỗ trợ bởi kiểm tra hợp lệ đã đạt là một báo cáo bạn có thể bảo vệ khi bị chất vấn. Nó cho khách hàng thấy không chỉ tổng số mà còn rằng tổng số đã được kiểm tra theo quy tắc trước khi gửi đi.",
    "cases.validate_estimate.step.validate.in.bill": "Bảng giá đã rà soát",
    "cases.validate_estimate.step.validate.in.rules": "Bộ quy tắc kiểm tra hợp lệ",
    "cases.validate_estimate.step.validate.out.issues": "Lỗi và cảnh báo đã liên kết",
    "cases.validate_estimate.step.validate.out.score": "Điểm đèn giao thông",
    "cases.validate_estimate.step.validate.title": "Chạy các quy tắc kiểm tra hợp lệ",
    "cases.validate_estimate.step.validate.what": "Chạy các bộ quy tắc trên bảng giá và đọc kết quả đèn giao thông. Mỗi lỗi và cảnh báo được liên kết với đúng hạng mục, để bạn có thể nhảy đến dòng vi phạm và sửa nguyên nhân thay vì triệu chứng.",
    "cases.validate_estimate.step.validate.why": "Khối lượng thiếu, giá bằng không, dòng trùng lặp và đơn giá nằm ngoài biên độ hợp lý là những lỗi rẻ để sửa hôm nay và khó giải thích sau khi phát hành. Điểm số là tín hiệu đi hay không đi trung thực của bạn.",
    "cases.validate_estimate.title": "Kiểm tra một dự toán trước khi gửi đi",
    "cases.verify_as_built_against_the_model_with_a_scan.desc": "Tải bản quét công trường, chồng mô hình thiết kế lên để phát hiện nơi công trình đã lệch khỏi mô hình, và lập biên bản kiểm tra bất cứ nơi nào hoàn công nằm ngoài dung sai.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.in.deviation": "Độ lệch đã đo",
