    "demo_banner.modal_install_box_label": "Cài đặt cục bộ - 3 commands",
    "demo_banner.modal_cta": "Tôi đã hiểu, tiếp tục",
    "sidebar.video_news.title": "Uber hóa ngành xây dựng",
