    "risk.boq_empty": "Bảng khối lượng này chưa có hạng mục được định giá. Hãy thêm các hạng mục có chi phí để chạy mô phỏng.",
    "risk.positions_loaded_msg": "{{count}} hạng mục có chi phí đã sẵn sàng để mô phỏng",
    "risk.default_optimistic": "Lạc quan mặc định",
